#!/usr/bin/env pwsh\n\n# Script de Setup Automático - Locadora\n# Este script configura o banco de dados e inicia o backend\n\nWrite-Host \"========================================\" -ForegroundColor Green\nWrite-Host \"  CONFIGURADOR AUTOMÁTICO - LOCADORA   \" -ForegroundColor Green\nWrite-Host \"========================================\" -ForegroundColor Green\nWrite-Host \"\"\n\n# 1. Verificar PostgreSQL\nWrite-Host \"[1/5] Verificando PostgreSQL...\" -ForegroundColor Cyan\n$pg = Get-Process postgres -ErrorAction SilentlyContinue\nif ($pg) {\n    Write-Host \"✅ PostgreSQL está rodando\" -ForegroundColor Green\n} else {\n    Write-Host \"❌ PostgreSQL não está rodando\" -ForegroundColor Red\n    Write-Host \"   Abra Services do Windows e inicie o serviço PostgreSQL\" -ForegroundColor Yellow\n    Exit 1\n}\n\n# 2. Verificar arquivo .env\nWrite-Host \"`n[2/5] Verificando arquivo .env...\" -ForegroundColor Cyan\nif (Test-Path \"backend/.env\") {\n    Write-Host \"✅ Arquivo .env encontrado\" -ForegroundColor Green\n    Get-Content \"backend/.env\" | Select-String -Pattern \"^DB_\" | ForEach-Object {\n        Write-Host \"   $_\" -ForegroundColor DarkGray\n    }\n} else {\n    Write-Host \"❌ Arquivo .env não encontrado\" -ForegroundColor Red\n    Write-Host \"   Crie o arquivo backend/.env com as configurações de banco\" -ForegroundColor Yellow\n    Exit 1\n}\n\n# 3. Fazer backup de node_modules (opcional)\nWrite-Host \"`n[3/5] Instalando/Verificando dependências...\" -ForegroundColor Cyan\ncd backend\nif (-not (Test-Path \"node_modules\")) {\n    Write-Host \"   Instalando npm packages...\" -ForegroundColor Yellow\n    npm install | Out-Null\n} else {\n    Write-Host \"✅ npm packages já instalados\" -ForegroundColor Green\n}\ncd ..\n\n# 4. Limpar processos Node antigos\nWrite-Host \"`n[4/5] Limpando processos antigos...\" -ForegroundColor Cyan\n$nodeProcs = Get-Process node -ErrorAction SilentlyContinue\nif ($nodeProcs) {\n    Write-Host \"   Encerrando processos Node...\" -ForegroundColor Yellow\n    $nodeProcs | Stop-Process -Force\n    Start-Sleep -Seconds 2\n    Write-Host \"✅ Processos encerrados\" -ForegroundColor Green\n} else {\n    Write-Host \"✅ Nenhum processo Node em execução\" -ForegroundColor Green\n}\n\n# 5. Iniciar backend\nWrite-Host \"`n[5/5] Iniciando backend...\" -ForegroundColor Cyan\nWrite-Host \"\"\nWrite-Host \"========================================\" -ForegroundColor Green\nWrite-Host \"  INICIANDO NESTJS - BACKEND DEBUG    \" -ForegroundColor Green\nWrite-Host \"========================================\" -ForegroundColor Green\nWrite-Host \"\"\nWrite-Host \"Esperando conexão com banco de dados...\" -ForegroundColor Yellow\nWrite-Host \"Deixe rodando enquanto testa o frontend\" -ForegroundColor Yellow\nWrite-Host \"Press Ctrl+C para parar\" -ForegroundColor Yellow\nWrite-Host \"\"\n\ncd backend\nnpm run start:dev\n